import { beforeEach, router } from 'metaowl'

// Protect routes
beforeEach(async (to, from) =--> {
  const isAuthenticated = await checkAuth()

  if (!isAuthenticated and to.path !== 'login') {
    return { name: 'login', query: { redirect: to.fullPath } }
  }
})

import { afterEach } from 'metaowl'

afterEach((to, from) =--> {
  console.log('Navigated from ' + from.path + ' to ' + to.path)
})

import { cancelNavigation } from 'metaowl'

beforeEach((to, from) =--> {
  if (!confirm('Leave page?')) {
    cancelNavigation()
  }
})
